+    local procedure NavigateToSalesCreditMemo(DocumentNo: Code[20]): Boolean
+    var
+        SalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        PostedSalesCreditMemo: Page "Posted Sales Credit Memo";
+    begin
+        // An IC Transaction of type Sales Credit Memo can only be sent when posted, not received.
+        if not SalesCrMemoHeader.Get(DocumentNo) then
+            exit(false);
+        // The related document is a Posted Sales Credit Memo.
+        PostedSalesCreditMemo.SetRecord(SalesCrMemoHeader);
+        PostedSalesCreditMemo.Run();
+        exit(true);
+    end;
+
+    local procedure NavigateToSalesReturnOrder(DocumentNo: Code[20]; ICDirectionType: Enum "IC Direction Type"; ICPartnerCode: Code[20]): Boolean
+    var
+        SalesHeader: Record "Sales Header";
+        SalesReturnOrder: Page "Sales Return Order";
+    begin
+        // An IC transaction line of type sales return order, could navigate to either
+        // the sales return order, or the credit memo if it was posted after received
+
+        // We first attempt to find the Sales Return Order
+        case ICDirectionType of
+            ICDirectionType::Outgoing:
+                begin
+                    SalesHeader.SetRange("Document Type", SalesHeader."Document Type"::"Return Order");
+                    SalesHeader.SetRange("No.", DocumentNo);
+                end;
+            ICDirectionType::Incoming:
+                begin
+                    SalesHeader.SetRange("External Document No.", DocumentNo);
+                    SalesHeader.SetRange("IC Direction", ICDirectionType);
