+    local procedure IsSupplyPlannedForReservation(ReservationEntry: Record "Reservation Entry"): Boolean
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // Check if the counterpart of this reservation (the supply side) is already planned.
+        // This prevents conflicting suggestions when items are consumed in multiple subassemblies.
+        // If the demand comes from a Prod. Order Component and the supply is from a Prod. Order Line,
+        // check if that prod order line is already planned in the worksheet.
+        
+        if ReservationEntry.Positive then
+            exit(false);
+        
+        if ReservationEntry."Source Type" <> Database::"Prod. Order Component" then
+            exit(false);
+        
+        // Get the counterpart reservation entry (supply side)
+        if not ReservationEntry.Get(ReservationEntry."Entry No.", true) then
+            exit(false);
+        
+        // If supply is from a Prod. Order Line, check if it's already planned
+        if ReservationEntry."Source Type" <> Database::"Prod. Order Line" then
+            exit(false);
+        
+        // Check if this prod order line is referenced in any requisition line
+        RequisitionLine.SetRange("Ref. Order Type", RequisitionLine."Ref. Order Type"::"Prod. Order");
+        RequisitionLine.SetRange("Ref. Order Status", ReservationEntry."Source Subtype");
+        RequisitionLine.SetRange("Ref. Order No.", ReservationEntry."Source ID");
+        RequisitionLine.SetRange("Ref. Line No.", ReservationEntry."Source Prod. Order Line");
+        
+        exit(not RequisitionLine.IsEmpty());
+    end;
